    ypixel: u16 align(1),
};

pub const IdentifyFlags = packed struct(u32) {
    utf8: bool = false,
    control_mode: bool = false,
    terminal_256: bool = false,
    _padding: u29 = 0,
};

pub const ResizeMsg = extern struct {
    cols: u16 align(1),
    rows: u16 align(1),
    xpixel: u16 align(1),
    ypixel: u16 align(1),
};

pub const KeyMsg = extern struct {
    key: u64 align(1),
    mouse_x: u16 align(1),
    mouse_y: u16 align(1),
    mouse_button: u8 align(1),
    mouse_flags: u8 align(1),
};

