3	/// Events produced by the input parser.
4	pub const InputEvent = union(enum) {
5	    print: u21,
6	    c0: u8,
7	    csi: CSI,
8	    osc: OSC,
9	    esc: ESC,
10	    dcs: DCS,
11	};
12	
13	pub const CSI = struct {
14	    final: u8,
15	    intermediates: [4]u8 = .{ 0, 0, 0, 0 },
16	    intermediate_count: u3 = 0,
17	    params: [16]u16 = .{0} ** 16,
18	    param_count: u5 = 0,
19	
20	    pub fn getParam(self: *const CSI, index: usize, default: u16) u16 {
21	        if (index >= self.param_count) return default;
22	        const val = self.params[index];
23	        return if (val == 0) default else val;
24	    }
25	};
26	
27	pub const OSC = struct {
28	    ps: u16,
29	    data: [256]u8 = .{0} ** 256,
30	    data_len: u16 = 0,
31	
32	    pub fn getData(self: *const OSC) []const u8 {
33	        return self.data[0..self.data_len];
34	    }
35	};
36	
37	pub const ESC = struct {
38	    final: u8,
39	    intermediate: u8 = 0,
40	};
41	
42	pub const DCS = struct {
43	    final: u8,
44	    intermediates: [4]u8 = .{ 0, 0, 0, 0 },
45	    intermediate_count: u3 = 0,
46	    params: [16]u16 = .{0} ** 16,
47	    param_count: u5 = 0,
48	    data: [4096]u8 = .{0} ** 4096,
49	    data_len: u16 = 0,
50	
51	    pub fn getData(self: *const DCS) []const u8 {
52	        return self.data[0..self.data_len];
53	    }
54	};
55	
56	pub const State = enum {
57	    ground,
58	    escape,
59	    escape_intermediate,
60	    csi_entry,
61	    csi_param,
62	    csi_intermediate,
63	    csi_ignore,
64	    osc_string,
65	    dcs_entry,
66	    dcs_param,
67	    dcs_intermediate,
68	    dcs_passthrough,
69	    dcs_ignore,
70	};
71	
72	/// VT100/xterm escape sequence parser.
73	pub const Parser = struct {
74	    state: State = .ground,
75	    params: [16]u16 = .{0} ** 16,
76	    param_count: u5 = 0,
77	    intermediates: [4]u8 = .{ 0, 0, 0, 0 },
78	    intermediate_count: u3 = 0,
79	    osc_buf: [256]u8 = .{0} ** 256,
80	    osc_len: u16 = 0,
81	    osc_ps: u16 = 0,
82	    osc_ps_done: bool = false,
83	    dcs_buf: [4096]u8 = .{0} ** 4096,
84	    dcs_len: u16 = 0,
85	    dcs_final: u8 = 0,
86	
87	    pub fn init() Parser {
88	        return .{};
89	    }
90	
91	    /// Feed one byte. Returns an event if a sequence is complete.
92	    pub fn feed(self: *Parser, byte: u8) ?InputEvent {
93	        if (byte == 0x1b) {
94	            self.resetSequence();
95	            self.state = .escape;
96	            return null;
97	        }
98	        if (byte == 0x18 or byte == 0x1a) {
99	            self.state = .ground;
100	            return null;
101	        }
102	
103	        return switch (self.state) {
104	            .ground => handleGround(byte),
105	            .escape => self.handleEscape(byte),
106	            .escape_intermediate => self.handleEscapeIntermediate(byte),
107	            .csi_entry => self.handleCsiEntry(byte),
108	            .csi_param => self.handleCsiParam(byte),
109	            .csi_intermediate => self.handleCsiIntermediate(byte),
110	            .csi_ignore => self.handleCsiIgnore(byte),
111	            .osc_string => self.handleOscString(byte),
112	            .dcs_entry => self.handleDcsEntry(byte),
113	            .dcs_param => self.handleDcsParam(byte),
114	            .dcs_intermediate => self.handleDcsIntermediate(byte),
115	            .dcs_passthrough => self.handleDcsPassthrough(byte),
116	            .dcs_ignore => null,
117	        };
118	    }
119	
120	    fn handleGround(byte: u8) ?InputEvent {
121	        if (byte < 0x20 or byte == 0x7f) return .{ .c0 = byte };
122	        return .{ .print = @as(u21, byte) };
123	    }
124	
125	    fn handleEscape(self: *Parser, byte: u8) ?InputEvent {
126	        if (byte == '[') {
127	            self.state = .csi_entry;
128	            return null;
129	        }
130	        if (byte == ']') {
131	            self.state = .osc_string;
132	            self.osc_len = 0;
133	            self.osc_ps = 0;
134	            self.osc_ps_done = false;
135	            return null;
136	        }
137	        if (byte == 'P') {
138	            self.state = .dcs_entry;
139	            return null;
140	        }
141	        if (byte >= 0x20 and byte <= 0x2f) {
142	            if (self.intermediate_count < 4) {
143	                self.intermediates[self.intermediate_count] = byte;
144	                self.intermediate_count += 1;
145	            }
146	            self.state = .escape_intermediate;
147	            return null;
148	        }
149	        if (byte >= 0x30 and byte <= 0x7e) {
150	            self.state = .ground;
151	            return .{ .esc = .{ .final = byte, .intermediate = if (self.intermediate_count > 0) self.intermediates[0] else 0 } };
152	        }
153	        self.state = .ground;
154	        return null;
155	    }
156	
157	    fn handleEscapeIntermediate(self: *Parser, byte: u8) ?InputEvent {
158	        if (byte >= 0x20 and byte <= 0x2f) {
159	            if (self.intermediate_count < 4) {
160	                self.intermediates[self.intermediate_count] = byte;
161	                self.intermediate_count += 1;
162	            }
163	            return null;
164	        }
165	        if (byte >= 0x30 and byte <= 0x7e) {
166	            self.state = .ground;
167	            return .{ .esc = .{ .final = byte, .intermediate = self.intermediates[0] } };
168	        }
169	        self.state = .ground;
170	        return null;
171	    }
