182	            if (self.param_count == 0) self.param_count = 1;
183	            if (self.param_count < 16) self.param_count += 1;
184	            return null;
185	        }
186	        if (byte == '?' or byte == '>' or byte == '<' or byte == '=') {
187	            if (self.intermediate_count < 4) {
188	                self.intermediates[self.intermediate_count] = byte;
189	                self.intermediate_count += 1;
190	            }
191	            self.state = .csi_param;
192	            return null;
193	        }
194	        if (byte >= 0x20 and byte <= 0x2f) {
195	            if (self.intermediate_count < 4) {
196	                self.intermediates[self.intermediate_count] = byte;
197	                self.intermediate_count += 1;
198	            }
199	            self.state = .csi_intermediate;
200	            return null;
201	        }
202	        if (byte >= 0x40 and byte <= 0x7e) return self.dispatchCsi(byte);
203	        self.state = .csi_ignore;
204	        return null;
205	    }
