207	    fn handleCsiParam(self: *Parser, byte: u8) ?InputEvent {
208	        if (byte >= '0' and byte <= '9') {
209	            if (self.param_count == 0) self.param_count = 1;
210	            const idx = self.param_count - 1;
211	            self.params[idx] = self.params[idx] *| 10 +| (byte - '0');
212	            return null;
213	        }
214	        if (byte == ';') {
215	            if (self.param_count < 16) self.param_count += 1;
216	            return null;
217	        }
218	        if (byte >= 0x20 and byte <= 0x2f) {
219	            if (self.intermediate_count < 4) {
220	                self.intermediates[self.intermediate_count] = byte;
221	                self.intermediate_count += 1;
222	            }
223	            self.state = .csi_intermediate;
224	            return null;
225	        }
226	        if (byte >= 0x40 and byte <= 0x7e) return self.dispatchCsi(byte);
227	        self.state = .csi_ignore;
228	        return null;
229	    }
