232	        if (byte >= 0x20 and byte <= 0x2f) {
233	            if (self.intermediate_count < 4) {
234	                self.intermediates[self.intermediate_count] = byte;
235	                self.intermediate_count += 1;
236	            }
237	            return null;
238	        }
239	        if (byte >= 0x40 and byte <= 0x7e) return self.dispatchCsi(byte);
240	        self.state = .csi_ignore;
