249	    fn dispatchCsi(self: *Parser, final: u8) InputEvent {
250	        const event = InputEvent{ .csi = .{
251	            .final = final,
252	            .intermediates = self.intermediates,
253	            .intermediate_count = self.intermediate_count,
254	            .params = self.params,
255	            .param_count = self.param_count,
256	        } };
