289	    fn handleDcsEntry(self: *Parser, byte: u8) ?InputEvent {
290	        if (byte >= '0' and byte <= '9') {
291	            self.state = .dcs_param;
292	            if (self.param_count == 0) self.param_count = 1;
293	            self.params[self.param_count - 1] = byte - '0';
