339	        if (byte >= 0x40 and byte <= 0x7e) {
340	            self.dcs_final = byte;
341	            self.state = .dcs_passthrough;
342	            return null;
343	        }
344	        if (byte >= 0x20 and byte <= 0x2f) return null;
345	        self.state = .dcs_ignore;
346	        return null;
