349	    fn handleDcsPassthrough(self: *Parser, byte: u8) ?InputEvent {
350	        if (byte == 0x9c) return self.dispatchDcs();
351	        if (self.dcs_len < self.dcs_buf.len) {
352	            self.dcs_buf[self.dcs_len] = byte;
353	            self.dcs_len += 1;
354	        }
355	        return null;
356	    }
