159	fn handleDecSet(scr: *Screen, csi: *const CSI, enable: bool) void {
160	    var i: u5 = 0;
161	    while (i < csi.param_count) : (i += 1) {
162	        switch (csi.params[i]) {
163	            1 => scr.mode.app_cursor = enable, // DECCKM
164	            6 => { // DECOM - origin mode
165	                scr.mode.origin = enable;
166	                scr.cursorTo(0, 0);
167	            },
