169	            25 => scr.mode.cursor_visible = enable, // DECTCEM
170	            47, 1047 => scr.mode.alt_screen = enable, // Alt screen
171	            1000 => scr.mode.mouse_standard = enable, // Mouse tracking
172	            1002 => scr.mode.mouse_button = enable, // Button event mouse
173	            1003 => scr.mode.mouse_any = enable, // Any event mouse
174	            1006 => scr.mode.mouse_sgr = enable, // SGR mouse
175	            1049 => { // Alt screen + save/restore cursor
176	                if (enable) {
177	                    scr.saveCursor();
178	                    scr.mode.alt_screen = true;
179	                } else {
180	                    scr.mode.alt_screen = false;
