201	fn handleSGR(scr: *Screen, csi: *const CSI) void {
202	    if (csi.param_count == 0) {
203	        // ESC[m = reset all attributes
204	        scr.cell.fg = .default;
205	        scr.cell.bg = .default;
206	        scr.cell.attrs = .{};
207	        return;
208	    }
209	
210	    var i: u5 = 0;
211	    while (i < csi.param_count) : (i += 1) {
212	        const p = csi.params[i];
213	        switch (p) {
214	            0 => { // Reset
215	                scr.cell.fg = .default;
216	                scr.cell.bg = .default;
217	                scr.cell.attrs = .{};
218	            },
219	            1 => scr.cell.attrs.bold = true,
220	            2 => scr.cell.attrs.dim = true,
221	            3 => scr.cell.attrs.italic = true,
222	            4 => scr.cell.attrs.underline = true,
223	            5 => scr.cell.attrs.blink = true,
224	            7 => scr.cell.attrs.reverse = true,
225	            8 => scr.cell.attrs.hidden = true,
226	            9 => scr.cell.attrs.strikethrough = true,
227	            21 => scr.cell.attrs.bold = false,
228	            22 => {
229	                scr.cell.attrs.bold = false;
230	                scr.cell.attrs.dim = false;
231	            },
232	            23 => scr.cell.attrs.italic = false,
233	            24 => scr.cell.attrs.underline = false,
234	            25 => scr.cell.attrs.blink = false,
235	            27 => scr.cell.attrs.reverse = false,
236	            28 => scr.cell.attrs.hidden = false,
237	            29 => scr.cell.attrs.strikethrough = false,
238	            // Foreground colors
239	            30...37 => scr.cell.fg = .{ .palette = @intCast(p - 30) },
240	            38 => {
241	                if (parseSgrColor(csi, &i)) |c| scr.cell.fg = c;
242	            },
243	            39 => scr.cell.fg = .default,
244	            // Background colors
245	            40...47 => scr.cell.bg = .{ .palette = @intCast(p - 40) },
246	            48 => {
247	                if (parseSgrColor(csi, &i)) |c| scr.cell.bg = c;
248	            },
249	            49 => scr.cell.bg = .default,
250	            // Bright foreground
251	            90...97 => scr.cell.fg = .{ .palette = @intCast(p - 90 + 8) },
252	            // Bright background
253	            100...107 => scr.cell.bg = .{ .palette = @intCast(p - 100 + 8) },
254	            else => {},
255	        }
256	    }
257	}
