259	/// Parse 256-color or RGB color from SGR params (38;5;N or 38;2;R;G;B).
260	fn parseSgrColor(csi: *const CSI, i: *u5) ?colour.Colour {
261	    if (i.* + 1 >= csi.param_count) return null;
262	    i.* += 1;
263	    switch (csi.params[i.*]) {
264	        5 => { // 256-color: 38;5;N
265	            if (i.* + 1 >= csi.param_count) return null;
266	            i.* += 1;
267	            return .{ .palette = @intCast(csi.params[i.*]) };
268	        },
269	        2 => { // RGB: 38;2;R;G;B
270	            if (i.* + 3 >= csi.param_count) return null;
271	            i.* += 1;
272	            const r: u8 = @intCast(@min(csi.params[i.*], 255));
273	            i.* += 1;
274	            const g: u8 = @intCast(@min(csi.params[i.*], 255));
275	            i.* += 1;
276	            const b: u8 = @intCast(@min(csi.params[i.*], 255));
277	            return .{ .rgb = .{ .r = r, .g = g, .b = b } };
278	        },
279	        else => return null,
280	    }
281	}
