335	    try std.testing.expectEqual(colour.Colour{ .palette = 1 }, scr.cell.fg);
336	
337	    // ESC[0m -> reset
338	    processBytes(&parser, &scr, "\x1b[0m");
339	    try std.testing.expectEqual(colour.Colour.default, scr.cell.fg);
340	}
