342	test "process print and linefeed" {
343	    var scr = Screen.init(std.testing.allocator, 80, 24, 0);
344	    defer scr.deinit();
345	    var parser = input.Parser.init();
346	
347	    processBytes(&parser, &scr, "AB");
348	    try std.testing.expectEqual(@as(u32, 2), scr.cx);
349	    try std.testing.expectEqual(@as(u21, 'A'), scr.grid.getCell(0, 0).codepoint);
350	    try std.testing.expectEqual(@as(u21, 'B'), scr.grid.getCell(1, 0).codepoint);
351	
352	    processBytes(&parser, &scr, "\r\n"); // CR LF
353	    try std.testing.expectEqual(@as(u32, 0), scr.cx);
354	    try std.testing.expectEqual(@as(u32, 1), scr.cy);
355	}
356	
357	test "process DEC private modes" {
358	    var scr = Screen.init(std.testing.allocator, 80, 24, 0);
359	    defer scr.deinit();
360	    var parser = input.Parser.init();
361	
362	    // Hide cursor
363	    processBytes(&parser, &scr, "\x1b[?25l");
364	    try std.testing.expect(!scr.mode.cursor_visible);
365	
366	    // Show cursor
367	    processBytes(&parser, &scr, "\x1b[?25h");
368	    try std.testing.expect(scr.mode.cursor_visible);
369	}
