371	test "process erase" {
372	    var scr = Screen.init(std.testing.allocator, 10, 3, 0);
373	    defer scr.deinit();
374	    var parser = input.Parser.init();
375	
376	    // Write some text
377	    processBytes(&parser, &scr, "ABCDEFGHIJ");
378	    // Move to col 5, erase to EOL
379	    processBytes(&parser, &scr, "\x1b[1;6H"); // row 1, col 6
380	    processBytes(&parser, &scr, "\x1b[K");
381	    try std.testing.expectEqual(@as(u21, 'E'), scr.grid.getCell(4, 0).codepoint);
382	    try std.testing.expectEqual(@as(u21, ' '), scr.grid.getCell(5, 0).codepoint);
383	}
