        return null;
    }

    fn handleCsiIntermediate(self: *Parser, byte: u8) ?InputEvent {
        if (byte >= 0x20 and byte <= 0x2f) {
            if (self.intermediate_count < 4) {
                self.intermediates[self.intermediate_count] = byte;
                self.intermediate_count += 1;
