    self.cx = 0;
    self.cy = 0;
    self.cstyle = self.default_cstyle;
    self.rupper = 0;
    self.rlower = self.grid.rows -| 1;
    self.cell = Cell.blank;
    self.mode = self.default_mode;
    self.saved = .{};

