1	const std = @import("std");
2	const grid_mod = @import("grid.zig");
3	const screen_mod = @import("screen.zig");
4	const output_mod = @import("../terminal/output.zig");
5	const colour = @import("../core/colour.zig");
6	
7	const Cell = grid_mod.Cell;
8	const Screen = screen_mod.Screen;
9	const Output = output_mod.Output;
10	
11	/// Tracks which lines need redrawing.
12	pub const DirtyTracker = struct {
13	    dirty: []bool,
14	    force_full: bool,
15	    allocator: std.mem.Allocator,
16	
17	    pub fn init(alloc: std.mem.Allocator, rows: u32) !DirtyTracker {
18	        const dirty = try alloc.alloc(bool, rows);
19	        @memset(dirty, true); // initially everything is dirty
20	        return .{
21	            .dirty = dirty,
22	            .force_full = true,
23	            .allocator = alloc,
24	        };
25	    }
26	
27	    pub fn deinit(self: *DirtyTracker) void {
28	        self.allocator.free(self.dirty);
29	    }
30	
31	    pub fn markDirty(self: *DirtyTracker, y: u32) void {
32	        if (y < self.dirty.len) self.dirty[y] = true;
33	    }
34	
35	    pub fn markAllDirty(self: *DirtyTracker) void {
36	        @memset(self.dirty, true);
37	        self.force_full = true;
38	    }
39	
40	    pub fn isDirty(self: *const DirtyTracker, y: u32) bool {
41	        if (self.force_full) return true;
42	        if (y >= self.dirty.len) return false;
43	        return self.dirty[y];
44	    }
45	
46	    pub fn clearDirty(self: *DirtyTracker) void {
47	        @memset(self.dirty, false);
48	        self.force_full = false;
49	    }
50	
51	    pub fn resize(self: *DirtyTracker, new_rows: u32) !void {
52	        const new_dirty = try self.allocator.alloc(bool, new_rows);
53	        @memset(new_dirty, true);
54	        self.allocator.free(self.dirty);
55	        self.dirty = new_dirty;
56	        self.force_full = true;
57	    }
58	};
59	
60	/// Redraw dirty lines from screen to output.
61	pub fn redraw(tracker: *DirtyTracker, scr: *Screen, out: *Output) void {
62	    var cur_fg: colour.Colour = .default;
63	    var cur_bg: colour.Colour = .default;
64	    var cur_attrs: colour.Attributes = .{};
65	
66	    // Reset attributes at start
67	    out.attrReset();
68	
69	    var y: u32 = 0;
70	    while (y < scr.grid.rows) : (y += 1) {
71	        if (!tracker.isDirty(y)) continue;
72	
73	        out.cursorTo(0, y);
74	        const line = scr.grid.getLine(y);
75	
76	        var x: u32 = 0;
77	        while (x < scr.grid.cols) : (x += 1) {
78	            const cell = &line.cells[x];
79	
80	            // Skip empty cells (width 0, used for wide char continuation)
81	            if (cell.width == 0 and cell.codepoint == 0) {
82	                continue;
83	            }
84	
85	            // Update attributes if changed
86	            if (@as(u16, @bitCast(cell.attrs)) != @as(u16, @bitCast(cur_attrs))) {
87	                out.attrReset();
88	                out.setAttrs(cell.attrs);
89	                cur_fg = .default;
90	                cur_bg = .default;
91	                cur_attrs = cell.attrs;
92	            }
93	
94	            // Update colors if changed
95	            if (!colourEql(cell.fg, cur_fg)) {
96	                out.setFg(cell.fg);
97	                cur_fg = cell.fg;
98	            }
99	            if (!colourEql(cell.bg, cur_bg)) {
100	                out.setBg(cell.bg);
101	                cur_bg = cell.bg;
102	            }
103	
104	            // Write character
105	            if (cell.codepoint >= 0x20) {
106	                var utf8_buf: [4]u8 = undefined;
107	                const len = std.unicode.utf8Encode(cell.codepoint, &utf8_buf) catch 1;
108	                out.writeBytes(utf8_buf[0..len]);
109	            } else {
110	                out.writeBytes(" ");
111	            }
112	        }
113	
114	        // Clear to end of line
115	        out.clearToEol();
116	    }
117	
118	    // Position cursor
119	    out.cursorTo(scr.cx, scr.cy);
120	
121	    // Show/hide cursor
122	    if (scr.mode.cursor_visible) {
123	        out.showCursor();
124	    } else {
125	        out.hideCursor();
126	    }
127	
128	    out.flush();
129	    tracker.clearDirty();
130	}
